{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The total opposition to the flow of electric current within a specific component or conductor, measured in Ohms (Ω).",
      "anchor": "Think of it as the electrical 'friction' created by a specific piece of wire or a lightbulb.",
      "misconception": "The belief that only 'resistors' have resistance; in reality, every cable and connection in a circuit has some resistance."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "A fundamental property of a material that describes how strongly it opposes current, regardless of its shape or size.",
      "anchor": "Like the 'roughness' of a material—copper has low resistivity, while rubber has very high resistivity.",
      "misconception": "Thinking resistivity changes if you cut a wire in half; resistivity is a constant for the material itself, only the total resistance changes."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (potential difference) as current passes through a resistance.",
      "anchor": "Similar to how water pressure drops between the start and the end of a very long garden hose.",
      "misconception": "The idea that voltage drop means electricity is 'leaking' out of the wire; it actually represents energy being converted into heat."
    },
    {
      "term": "Cross-sectional Area",
      "simpleDefinition": "The 'thickness' or surface area of the end of a conductor, usually measured in mm².",
      "anchor": "A wider pipe allows more water to flow; a larger cross-sectional area allows more current to flow with less resistance.",
      "misconception": "Confusing the diameter of the wire with the total cross-sectional area."
    },
    {
      "term": "Factors of Resistance",
      "simpleDefinition": "The four physical properties that determine a conductor's resistance: Length, Area, Material (Resistivity), and Temperature.",
      "anchor": "The 'L.A.M.T.' rule for remembering what makes a wire harder or easier for current to pass through.",
      "misconception": "Assuming that only the length of a cable matters when calculating resistance."
    }
  ],
  "anchorPhrases": [
    "Resistance is the opposition to current flow.",
    "Resistivity is a fixed property of the material itself.",
    "Voltage drop is the energy used up pushing current through a resistance.",
    "Resistance depends on length, area, material, and temperature."
  ],
  "misconceptionTargets": [
    "Using the terms resistance and resistivity interchangeably.",
    "Believing that voltage drop indicates a loss of electrons rather than a loss of pressure.",
    "Assuming resistivity changes based on the physical dimensions of the conductor."
  ]
}

{
  "teachChecks": [
    {
      "title": "The Nature of Resistance",
      "basicQuestions": [
        {
          "questionText": "What term describes the total opposition to the flow of electric current within a circuit?",
          "answerGuidance": [
            "Resistance",
            "Electrical resistance"
          ],
          "hint": "Think of the term for opposition to current flow.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the unit of measurement for electrical resistance?",
          "answerGuidance": [
            "Ohm",
            "Ohms",
            "Ω"
          ],
          "hint": "It is named after a scientist and uses a Greek symbol.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What physical effect does resistance resemble when electrons collide with atoms in a conductor?",
          "answerGuidance": [
            "Friction",
            "Electrical friction"
          ],
          "hint": "Think of the mechanical term for two things rubbing together and slowing down.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically incorrect to claim that only specific 'resistor' components provide resistance in an electrical installation?",
      "deeperAnswerGuidance": [
        "Every conductor has resistance",
        "Cables and connections oppose current flow",
        "Resistance is a property of all circuit parts",
        "It is not limited to specific components"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider whether the wiring itself allows current to flow perfectly without any opposition."
    },
    {
      "title": "The Property of Resistivity",
      "basicQuestions": [
        {
          "questionText": "Which term refers to the inherent property of a material that describes its opposition to current regardless of its shape?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the material constant, not the total opposition of the object.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What Greek letter is used as the symbol for resistivity?",
          "answerGuidance": [
            "Rho",
            "ρ"
          ],
          "hint": "It looks like a lowercase 'p'.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "If you cut a length of copper wire in half, what happens to the resistivity of the metal?",
          "answerGuidance": [
            "Stays the same",
            "Remains constant",
            "No change"
          ],
          "hint": "Resistivity is a property of the material itself, not its dimensions.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "How does resistivity function as a 'constant' compared to the variable nature of resistance in a circuit?",
      "deeperAnswerGuidance": [
        "Resistivity is fixed for the material type",
        "It does not change with shape or size",
        "Resistance changes if dimensions change",
        "Resistivity is an inherent quality of the substance"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Think about what happens to the value if you change the length of the wire versus changing the metal it is made from."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "Which term is used to describe the 'recipe' or inherent quality of a material's opposition?",
          "answerGuidance": [
            "Resistivity"
          ],
          "hint": "This is the material property, not the final measurement of the wire.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What happens to the total resistance of a conductor if its length is increased?",
          "answerGuidance": [
            "Increases",
            "Higher resistance",
            "It goes up"
          ],
          "hint": "Think about electrons having to travel a further distance.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which term describes the actual, measured opposition found in a specific run of cable?",
          "answerGuidance": [
            "Resistance"
          ],
          "hint": "This is the 'result' based on the material and its shape.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why can two conductors made of the same material (such as copper) have completely different resistance values?",
      "deeperAnswerGuidance": [
        "Resistance depends on physical dimensions",
        "Length and thickness affect the result",
        "Resistivity is the same but shape varies",
        "One wire might be longer or thinner than the other"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3"
      ],
      "hint": "Consider the factors other than the material type that contribute to the final resistance value."
    },
    {
      "title": "The Meaning of Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What term describes the loss of electrical pressure as current passes through a resistance?",
          "answerGuidance": [
            "Voltage drop"
          ],
          "hint": "Think about the 'drop' in potential across a component.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Into what form of energy is the 'lost' electrical potential usually converted within a conductor?",
          "answerGuidance": [
            "Heat",
            "Thermal energy"
          ],
          "hint": "Think about what happens to a wire when it has to work hard to push current through.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What is the formal term for the electrical 'pressure' that is reduced during a voltage drop?",
          "answerGuidance": [
            "Potential difference"
          ],
          "hint": "It is the difference in electrical potential between two points.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        }
      ],
      "deeperQuestionText": "If a circuit experiences excessive voltage drop in the supply cables, why might the connected equipment fail to operate correctly?",
      "deeperAnswerGuidance": [
        "Insufficient electrical pressure reaches the load",
        "Energy is lost as heat in the cables",
        "The potential difference at the equipment is too low",
        "The energy was used up pushing current through the wire resistance"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP4"
      ],
      "hint": "Think about the energy required to move current and what is left for the actual device at the end of the cable."
    },
    {
      "title": "Factors Affecting Resistance",
      "basicQuestions": [
        {
          "questionText": "In the acronym L.A.M.T., what does the letter 'A' stand for?",
          "answerGuidance": [
            "Area",
            "Cross-sectional area"
          ],
          "hint": "This refers to the thickness or size of the end of the wire.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP3"
          ]
        },
        {
          "questionText": "How does increasing the cross-sectional area of a cable affect its resistance?",
          "answerGuidance": [
            "Decreases",
            "Lower resistance",
            "Reduces resistance"
          ],
          "hint": "Think about a wider pipe allowing more flow.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What usually happens to the resistance of a metal conductor as its temperature rises?",
          "answerGuidance": [
            "Increases",
            "Higher resistance",
            "It goes up"
          ],
          "hint": "Heat makes it harder for electrons to flow through most metals.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "Why must an electrician consider both the material type and the length of a cable when calculating the expected voltage drop for a circuit?",
      "deeperAnswerGuidance": [
        "Both factors determine the total resistance",
        "Material sets the resistivity constant",
        "Length multiplies the total opposition",
        "Resistance is the cause of voltage drop"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Consider how the physical properties of the cable combine to create the resistance that 'uses up' the voltage."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice: Analyzing a Cable Run",
    "objective": "Explain the link between resistivity, resistance, and voltage drop in a specific scenario.",
    "retrievalTextLines": [
      "Scenario: You are installing a 25-metre run of aluminum cable for a sub-main circuit.",
      "Recall the 3-step logic from the worked example:",
      "1. The material (Aluminum) has a fixed property called resistivity.",
      "2. The length (25m) and thickness (area) of that aluminum create the total resistance.",
      "3. The current fighting that resistance causes a loss of electrical pressure."
    ],
    "questionText": "Using the 25-metre aluminum cable scenario, explain how the material's resistivity and the cable's physical dimensions combine to result in a voltage drop at the end of the run.",
    "answerGuidance": [
      "The aluminum's resistivity is a constant material property that, when combined with the 25m length and cross-sectional area, creates the total resistance; as current flows through this resistance, electrical pressure is lost as heat, resulting in a voltage drop."
    ],
    "hint": "Start with the material property, move to the total opposition (resistance), and finish with the loss of pressure (voltage drop)."
  },
  "practice": {
    "title": "Practice: Defining Voltage Drop",
    "objective": "Define the cause and nature of voltage drop in a circuit.",
    "retrievalTextLines": [
      "Voltage drop is not a 'leak' of electrons.",
      "It is a measurable loss of potential difference (pressure) across a conductor or load.",
      "This occurs because energy is required to overcome the resistance of the material."
    ],
    "questionText": "Describe what is physically happening to the electrical energy as it passes through a conductor's resistance to cause a 'voltage drop'.",
    "answerGuidance": [
      "Electrical energy (potential difference or pressure) is being converted into heat energy as it overcomes the resistance of the conductor, leading to a reduction in voltage at the end of the circuit."
    ],
    "hint": "Think about what the electrical 'pressure' is being converted into as it fights against the resistance."
  }
}

{
  "integrative": {
    "title": "Integrative Close: The Cable-to-Load Relationship",
    "objective": "Synthesize the relationship between material choice (resistivity), conductor size (resistance), and the resulting loss of potential (voltage drop).",
    "retrievalTextLines": [
      "Resistivity (ρ) is the material's inherent opposition.",
      "Resistance (R) is the total opposition based on Length, Area, Material, and Temperature (L.A.M.T.).",
      "Voltage drop is the loss of potential difference across that resistance."
    ],
    "questionText": "A long run of copper cable is providing power to a heater, but the heater is not reaching full temperature because of a significant voltage drop. Explain how the material's resistivity and the cable's physical dimensions (length and area) have combined to create this loss of electrical pressure.",
    "answerGuidance": [
      "The copper has an inherent resistivity (ρ) which, when combined with the long length and specific cross-sectional area, results in a total resistance (R) for the cable run. As current flows through this resistance, electrical energy is converted into heat, causing a loss of potential difference (voltage drop) before it reaches the heater."
    ],
    "hint": "Connect the material's constant property to the physical size of the wire, then explain what happens to the 'pressure' as it travels through that total resistance."
  }
}

